window.__QUIZ_DATA__=[{"id":"objective>Geography>2012>1","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IKOBI DISTRICT and use it to answer question 1 - 10    The scale of the map in statement form","images":["data:image/png;base64,"],"options":{"A":"1cm on the map represents 1 km on the ground","B":"1cm on the map represents 1 1/2 km on the ground","C":"1cm on the map represents 2 km on the ground","D":"1cm on the map represents 3 km on the ground"},"answer":"C","explanation":"The scale of the map given is 1cm on the map represents 2km on the ground","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>2","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The distance from Tango to IKOBI \"as the cro flies\" is","images":["data:image/png;base64,"],"options":{"A":"15 km","B":"20 km","C":"24 km","D":"30 km"},"answer":"B","explanation":"The distance from Tang to IKOBI \"as the crow flies is 7.5 cm which is equal to 15 km on the ground. You can measure this with your ruler.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>3","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The drainage pattern on the map is","images":["data:image/png;base64,"],"options":{"A":"dentritic","B":"centripetal","C":"radial","D":"annular"},"answer":"C","explanation":"The drainage pattern of the map given is a radial drainage pattern. It is a drainage pattern in which consequent streams radiate or diverge outward, like the spokes of a wheel from a high central area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>4","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The area on the map where many rivers took their source is a","images":["data:image/png;base64,"],"options":{"A":"lagoon","B":"watershed","C":"spring","D":"lake"},"answer":"D","explanation":"The area on the map where many rivers took their source is a lake.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>5","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"In which part of the map could a sawmill industry be sited?","images":["data:image/png;base64,"],"options":{"A":"North East","B":"North West","C":"South East","D":"South West"},"answer":"D","explanation":"The part of the map where saw mill industry can be sited is around the southwestern region because it is in that region that have forest where timber can be generated.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>6","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Which of the following is the most important town in the mapped area?","images":["data:image/png;base64,"],"options":{"A":"Ojoi","B":"IKOBI","C":"Tang","D":"Zabasan"},"answer":"B","explanation":"The most important town in the mapped area is   IKOBI, the reason being that it contains market, schools, roads, court and it is also a built up area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>7","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"IKOBI is an example of a","images":["data:image/png;base64,"],"options":{"A":"mining settlement","B":"nucleated settlement","C":"dispersed settlement","D":"linear settlement"},"answer":"B","explanation":"IKOBI is an example of a nucleated settlement. A nucleated settlement is one (a town) where buildings are close together, often clustered around a central point.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>8","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The bearing of Ojoi from IKOBI is","images":["data:image/png;base64,"],"options":{"A":"45o","B":"95o","C":"270o","D":"315o"},"answer":"D","explanation":"The bearing of Ojo: from IKOBI is greater than 270o, it is within NW. So that is 315o.    = 315o (90o+90o+90o+45o)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>9","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The likely occupation of the inhabitants of Tang is","images":["data:image/png;base64,"],"options":{"A":"farming","B":"lumbering","C":"fishing","D":"trading"},"answer":"A","explanation":"The likely occupation of the inhabitants of Tang is farming. If we consider the keys that are embedded within the location. We have the keys for the following features:  (1) School   (2) Built up area   (3) Grass land    Hence, we can conclude that their major occupation is farming (because of the presence of grass land)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>10","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Which of the following towns intervisible?","images":["data:image/png;base64,"],"options":{"A":"IKOBI and Tang","B":"Ojoi and IKOBI","C":"Ojoi and Tang","D":"Ture and IKOBI"},"answer":"A","explanation":"IKOBI and tang are intervisible since there is no obstruction between the two locations","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>11","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is a satelite of the Earth?","images":[],"options":{"A":"Moon","B":"Sun","C":"Jupital","D":"Mercury"},"answer":"A","explanation":"Moon is a satellite of the Earth. Note a satellite refers to a smaller body or orbiting around a larger one.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>12","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Mid latitude region are found between","images":[],"options":{"A":"latitude 30o and 45o north only","B":"latitude 30o and 45o north and south","C":"latitudes 0o and 23 1/2 o north and south","D":"latitudes 30o and 45o south only"},"answer":"B","explanation":"Mid-latitude regions are found between latitude 30\u00b0 and 45\u00b0 north and south. The mid-latitudes are the latitudes between 30\u00b0 and 60\u00b0 in both hemispheres. They are often referred to as the temperate zone because the climate is less extreme than in the tropics or the polar regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>13","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The outer layer of the solid earth is called the","images":[],"options":{"A":"core","B":"atmosphere","C":"crust","D":"hydrosphere"},"answer":"C","explanation":"The outer layer of the solid earth is called the crust: it is the outermost of the lithosphere (solid earth)","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>14","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is an evidence to show that the earth is spherical in shape? The","images":[],"options":{"A":"eccliptical orbit","B":"Earth's curved horizon","C":"revolution of the earth","D":"seasonal change"},"answer":"B","explanation":"(1) Circular horizon (Earth's curved horizon)  (2) Ship visibility (3) Sunrise and sunset   (4) Circum-navigation of the Earth, etc. are some of the evidences to show that the Earth is spherical.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>15","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following is an igneous rock?","images":[],"options":{"A":"Sandstone","B":"Granite","C":"Chalk","D":"Limestone"},"answer":"B","explanation":"Igneous rock is one of the major groups of rock that makes up the crust of the Earth; formed by the cooling of molten magma, either below the surface (intrusive) or on the surface (extrusive). Granite is a group of igneous plutonic rocks composed primarily of field spar and quartz","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>16","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Bedding plane is a characteristic of","images":[],"options":{"A":"sedimentary rocks","B":"igneous rock","C":"metamorphic rocks","D":"volcanic rocks"},"answer":"A","explanation":"Bedding plane refers to the surface that separates each successive layer of a stratified rock from its proceeding layer. It is a plane of stratification. It is found in sedimentary rocks.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>17","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following landforms may occur when large scale horizontal earth movement and stresses are set in the earth's crust?","images":[],"options":{"A":"Block mountains","B":"Fold mountains","C":"Volcanic mountains","D":"Residual mountains"},"answer":"B","explanation":"Fold mountains may occur when large scale horizontal earth movements and stresses are set up in the earth's crust.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2012>18","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Mechanical weathering due to changes in temperature occurs mainly in","images":[],"options":{"A":"coastal areas","B":"desert regions","C":"wet equatorial regions","D":"polar region"},"answer":"B","explanation":"Mechanical weathering due to changes in temperature, also known as thermal weathering, occurs mainly in desert regions. This is because deserts experience extreme temperature changes between day and night, causing rocks to expand and contract. This repeated expansion and contraction causes the rock to crack and break apart.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>19","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The process by which rocks are broken down and not transported is termed","images":[],"options":{"A":"denudation","B":"earth movement","C":"weathering","D":"erosion"},"answer":"C","explanation":"Weathering is the process by which rocks are broken down in place, or 'in situ', by physical, chemical, and biological processes. Denudation refers to the overall effect of disintegration, wearing away, and removal of rock material. Earth movement refers to the movement of the Earth's crust, and erosion is the process of eroding or being eroded by wind, water, or other natural agents, which includes transportation of the eroded materials.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>20","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The wearing away of the sides and bottom of a river channels is called","images":[],"options":{"A":"corrosion","B":"suspension","C":"corrasion","D":"solution"},"answer":"C","explanation":"The main ways in which a river erodes are: Corrasion - wearing away of the river bed and banks by the load hitting against them. Attrition - wearing down of the load as the rocks and pebbles hit the river bed and each other, breaking into smaller and more rounded pieces","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>21","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Wind erosion is most common in","images":[],"options":{"A":"arid areas","B":"humid areas","C":"riverine areas","D":"rocky areas"},"answer":"A","explanation":"Wind erosion is most common in arid areas. This is because these areas have less vegetation cover to protect the soil from the wind. In humid areas, the soil is often too wet for significant wind erosion to occur. Riverine areas are more affected by water erosion, and rocky areas are typically too hard for significant wind erosion to occur.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>22","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"A piece of land almost surrounded by water is called","images":[],"options":{"A":"isthmus","B":"peninsula","C":"headland","D":"island"},"answer":"B","explanation":"A piece of land almost surrounded by water is a  peninsula . We may also say it is a piece of land projecting into water from  a larger land mass.   N.B: We chose \"Peninsule\" because of the word \"almost\".","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>23","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following pairs are associated with the upper course of a river? I. Delta II. Gorges III. Meanders IV. Rapids","images":[],"options":{"A":"I and II","B":"I and III","C":"II and III","D":"II and IV"},"answer":"D","explanation":"The upper course of a river is characterized by steep gradients, and features such as gorges and rapids. A gorge is a narrow valley with steep, rocky walls located between hills or mountains, typically with a stream or river running through it. Rapids are sections of a river where the river bed has a relatively steep gradient, causing an increase in water velocity and turbulence. A delta and meanders are features associated with the lower course of a river. A delta is a landform that forms from deposition of sediment carried by a river as the flow leaves its mouth and enters slower-moving or stagnant water. Meanders are a series of regular sinuous curves, bends, loops, turns, or windings in the channel of a river, stream, or other watercourse.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>24","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Steep sided and often dry valleys in the desert are called","images":[],"options":{"A":"wadis","B":"hamada","C":"mesa","D":"reg"},"answer":"A","explanation":"Wadis are steep-sided and often dry valleys in the desert. They are typically the product of powerful flash floods and water erosion processes. A hamada is a type of desert landscape consisting of high, largely barren, hard, rocky plateaus, while a mesa is an elevated area of land with a flat top and sides that are usually steep cliffs, and a reg is a desert surface covered with closely packed, interlocking angular or rounded rock fragments of pebble and cobble size.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>25","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"To obtain the climate of a place the average atmospheric weather conditions should be considered for about","images":[],"options":{"A":"45 years","B":"35 years","C":"24 years","D":"20 years"},"answer":"B","explanation":"To obtain the climate of a place, the average atmospheric weather conditions should be considered for about 24 years.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>26","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Isotherms are lines drawn on maps joining places having equal","images":[],"options":{"A":"rainfall","B":"cloudness","C":"pressure","D":"temperature"},"answer":"D","explanation":"Isotherms are line drawn on maps joining places having equal temperature.   We also have isobar (equal pressure).","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>27","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The difference between the temperatures of the hottest and coldest months of a place is the","images":[],"options":{"A":"length of the rainy season","B":"mean annual temperature","C":"annual range temperature","D":"total monthly temperature"},"answer":"C","explanation":"The difference between the temperature of the hottest and the coldest months of a place is the  annual range of temperature   N.B: \"Ranges\" means \"different\"","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>28","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Precipitation includes all the following except","images":[],"options":{"A":"dust","B":"dew","C":"snow","D":"fog"},"answer":"A","explanation":"Precipitation refers to any water, liquid or solid, that falls from the atmosphere and reaches the ground. Dust does not fall under this category.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>29","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Convectional rains are typical of","images":[],"options":{"A":"Polar areas","B":"Meditarranean areas","C":"Monsoon areas","D":"Equatorial areas"},"answer":"D","explanation":"Convectional rainfall, occurs due to thermal convection as a result of heating of the ground surface. It is common in Equatorial areas.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>30","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The environmental lapse rate is a decrease of temperature by","images":[],"options":{"A":"6.5oC for every 1,000 metres of ascent","B":"6.5 of for every 1,000 metres of ascent","C":"6.5 of for every 1,000 metres of descent","D":"6.5 oC for every 1,000 metres of descent"},"answer":"A","explanation":"The lapse rate of nonrising air - commonly referred to as the normal, or environmental lapse rate - is highly variable, being affected by radiation, convection and condensation; it averages about 6.5oC per kilometre (1000m) in the treposphere","marks":"1","difficulty":"3"},{"id":"objective>Geography>2012>31","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following statements is true of winds?","images":[],"options":{"A":"Off-shore winds are usually wet","B":"They blow strongly only in forest","C":"They blow from areas of high pressure to areas of low pressure","D":"They blow from areas of low pressure to areas of high pressure"},"answer":"C","explanation":"Winds blow due to pressure difference between two regions Wind blow from a high pressure region to a low pressure region.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>32","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"A vertical section of soil through all its horizons is called","images":[],"options":{"A":"soil texture","B":"A - horizon section","C":"B - horizon section","D":"soil profile"},"answer":"D","explanation":"A vertical section of soil through all its horizons is called a soil profile. The soil profile is a vertical cross-section of the soil, exposing the layers, or horizons. The soil profile is where the secrets of the soil and landscape around it are hidden.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>33","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Leaching of soil means","images":[],"options":{"A":"water logging of the soil","B":"formation of hardpan in the soil","C":"washing of nutrients down from the upper layers of the soil","D":"removal of parent materials from the soil"},"answer":"C","explanation":"Leaching in soil science refers to the loss of water-soluble plant nutrients from the soil, due to rain and irrigation. It is the process of washing of nutrients down from the upper layers of the soil. This can lead to nutrient deficiencies in the soil, which can affect plant growth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>34","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Which of these methods will best help to check wind erosion?","images":[],"options":{"A":"Re-afforestation and planting of trees as wind break","B":"Inter-cropping and contour ploughing","C":"Strip cropping and crop rotation","D":"Contour ploughing and manuring"},"answer":"A","explanation":"Wind erosion has to do with \"air\" and \"height\" we need to plant more trees (re-afforestation) as the wind break","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>35","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following are the most valuable products of Equatorial forest?","images":[],"options":{"A":"Tea, banana, oranges","B":"Cocoa, rubber, oil palm","C":"Cassava, plantain, rice","D":"Ginger, coffee, sisal"},"answer":"B","explanation":"Cocoa, rubber, and oil palm are the most valuable products of the Equatorial forest. The Equatorial forest, also known as the tropical rainforest, is characterized by high rainfall and temperature. It is the home of many valuable plant species including cocoa, rubber, and oil palm. These plants thrive in the hot and humid conditions of the Equatorial forest and are economically valuable for their various uses.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>36","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following is not a characteristic of the Rainforest?","images":[],"options":{"A":"It has tall trees with buttress roots and evergreen broad leaves","B":"It has deciduous trees and aerial roots","C":"The trees in it have different heights and layers of canopies","D":"some of its trees are climbers, creepers and epiphytes"},"answer":"B","explanation":"The statement that the Rainforest has deciduous trees and aerial roots is not a characteristic of the Rainforest. Rainforests are characterized by evergreen trees, not deciduous. Deciduous trees are those that shed their leaves annually, and they are typically found in temperate zones. Rainforests are evergreen because they do not have a dry season that would cause the trees to shed their leaves. Also, while some rainforest trees may have aerial roots, it is not a defining characteristic of rainforests.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>37","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Trees are deciduous when they","images":[],"options":{"A":"have thorny barks and fleshly leaves","B":"are in pure stands having just one types of species","C":"generally shed their leaves during one season of the year","D":"do not shed their leaves at any season of the year"},"answer":"C","explanation":"Deciduous trees are the type of trees that shed their leaves annually as an adaptation to adverse weather conditions. They are common in areas with a temperate climate. During the cold or dry season, these trees shed their leaves and enter a state of dormancy. This is a survival strategy, as it reduces the amount of energy they need to stay alive.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>38","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The Mediterranean vegetation is described as xerophytic vegetation because it is","images":[],"options":{"A":"beat resistant","B":"fire resistance","C":"wind resistance","D":"drought resistant"},"answer":"D","explanation":"Any vegetation that is drought resistant is Xerophytic or desert vegetation. And this is typical of Mediterranean vegetation","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>39","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The major difference between a nucleated settlement and a dispersed settlement is that a nucleated settlement","images":[],"options":{"A":"contains more buildings and people","B":"had buildings clustered together","C":"often occurs in regions of intensive farming","D":"is usually at the meeting point of many roads"},"answer":"B","explanation":"The major difference between a nucleated settlement and a dispersed settlement is the pattern of the buildings. In a nucleated settlement, buildings are clustered together, often around a central point like a market or a crossroads. This is in contrast to a dispersed settlement where buildings are spread out over a large area, often isolated from each other.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>40","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following best describes high population growth?","images":[],"options":{"A":"The number of deaths is equal to the number of births","B":"The birth rate is the same as the death rate","C":"The people moving out of an area are more than the people moving into it","D":"The birth rate is higher than the death rate"},"answer":"D","explanation":"When the population growth is high, it means the rate of natality (birth rate) exceeds the rate of mortality (death rate)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>41","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The low population density in the Middle Belt of West Africa resulted from all the following except","images":[],"options":{"A":"unfavourable climate","B":"the absence of heavy industries in the area","C":"inadequate infrastructure","D":"inadequacy of food in the area"},"answer":"D","explanation":"Inadequacy of food in the area is not responsible for low population density in the Middle. Belt of West Africa","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>42","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The busiest ocean trade route is the","images":[],"options":{"A":"Mozambique channel","B":"Suez canal route","C":"North Atlantic route","D":"Cape route"},"answer":"C","explanation":"The North Atlantic route is the busiest ocean trade route. It connects North America with Europe, two of the world's largest and most economically active continents. This route is heavily used for the transportation of goods, making it the busiest.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2012>43","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following industries is best located near the source of raw material?","images":[],"options":{"A":"Drug manufacturing","B":"Paint manufacturing","C":"Sugar refining","D":"Watch making"},"answer":"C","explanation":"Industries like sugar refining and mining industries are best located close to the source of raw material","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>44","subject":"Geography","year":"2012","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"A ginnery is a place where cotton is","images":[],"options":{"A":"planted","B":"woven into clothes","C":"processed to take out the seed","D":"stored for distribution"},"answer":"C","explanation":"A ginnery is a place where cotton is processed to take out the seed. The term 'ginnery' comes from 'gin', which is a machine that quickly and easily separates cotton fibers from their seeds, allowing for much greater productivity than manual cotton separation.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>45","subject":"Geography","year":"2012","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"One major advantage of plantation agriculture in East Africa is that it","images":[],"options":{"A":"involves high capital investment","B":"causes soil erosion","C":"provides regular supply of raw materials","D":"creates unemployment"},"answer":"C","explanation":"Plantation agriculture is a form of commercial farming where crops are grown for profit. In the options stated, we can infer that plantation agriculture supplies raw materials","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>46","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Which of the following is not associated with human intervention?","images":[],"options":{"A":"Mining","B":"Construction","C":"Rainfall","D":"Urbanization"},"answer":"C","explanation":"Rainfall is a natural phenomenon that occurs without human intervention, unlike the other options which are all activities carried out by humans.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2012>47","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map below to answer questions 47 to 50    The town marked B is","images":["data:image/png;base64,"],"options":{"A":"Bloemfontein","B":"cape town","C":"Durban","D":"Maputo"},"answer":"B","explanation":"The map is the map of Africa. The region marked is exactly in South-Africa, B is Cape Town, the legislative capital of South Africa","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>48","subject":"Geography","year":"2012","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The river marked O is the","images":["data:image/png;base64,"],"options":{"A":"Limpopo","B":"Zambezi","C":"Orange","D":"Congo"},"answer":"D","explanation":"The river marked O is river Congo. River Congo is a larger river in Africa which flows for about 4,380 km to the Atlantic Ocean in the Democratic Republic of Congo.   N.B: O is at the centre of the map. Hence, the river is in Central Africa, and in the options given, only River Congo is in Central Africa, Congo DR.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>49","subject":"Geography","year":"2012","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The area shaded and marked x is the","images":["data:image/png;base64,"],"options":{"A":"Red Sea","B":"Mediterranean Sea","C":"Isthmus of Suez","D":"Black Sea"},"answer":"A","explanation":"The area shaded and marked x is the Red Sea. Red Sea is a  long ,  narrow  sea between Africa and the Arabian peninsula; it links the Suez canal with the Arabian Sea.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2012>50","subject":"Geography","year":"2012","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The letter Y on the map represents","images":["data:image/png;base64,"],"options":{"A":"Durban","B":"Queenstown","C":"Johannesburg","D":"Bloemfontein"},"answer":"C","explanation":"The letter Y on the map represents Johannes burg   Note that Y is still in South Africa","marks":"1","difficulty":"2"}];